/* javascript.min.js */
const $=s=>document.querySelector(s),$$=s=>document.querySelectorAll(s);

const on=(e,t,f)=>e&&e.addEventListener(t,f);

const addClass=(e,c)=>e&&e.classList.add(c);
const removeClass=(e,c)=>e&&e.classList.remove(c);
const toggleClass=(e,c)=>e&&e.classList.toggle(c);

const show=e=>e&&(e.style.display="block");
const hide=e=>e&&(e.style.display="none");
const toggle=e=>e&&(e.style.display=e.style.display==="none"?"block":"none");

const html=(e,v)=>e&&(e.innerHTML=v);
const text=(e,v)=>e&&(e.textContent=v);
const val=(e,v)=>v!==undefined?(e.value=v):e.value;

const css=(e,p,v)=>e&&(e.style[p]=v);

const create=(t,c)=>{let e=document.createElement(t);if(c)e.className=c;return e};

const ready=f=>document.readyState!="loading"?f():document.addEventListener("DOMContentLoaded",f);

const ajax=(u,cb)=>fetch(u).then(r=>r.text()).then(d=>cb&&cb(d));

const storage={
  set:(k,v)=>localStorage.setItem(k,JSON.stringify(v)),
  get:k=>JSON.parse(localStorage.getItem(k)),
  del:k=>localStorage.removeItem(k)
};

const notify=(msg)=>{
  let n=create("div");
  n.textContent=msg;
  Object.assign(n.style,{
    position:"fixed",bottom:"20px",right:"20px",
    background:"#000",color:"#fff",padding:"10px 15px",
    borderRadius:"8px",boxShadow:"0 0 10px red",
    zIndex:9999
  });
  document.body.appendChild(n);
  setTimeout(()=>n.remove(),2000);
};
